class CloudApiService {
  final HttpService _httpService;
  final String baseUrl;

  CloudApiService({
    HttpService? httpService,
    this.baseUrl = NetworkConfig.cloudApiBaseUrl,
  }) : _httpService = httpService ?? HttpService();

  Future<Map<String, dynamic>> fetchData(String endpoint) async {
    return await _httpService.get('$baseUrl/$endpoint', retry: true);
  }

  Future<Map<String, dynamic>> createResource(
    String endpoint,
    Map<String, dynamic> data,
  ) async {
    return await _httpService.post('$baseUrl/$endpoint', body: data);
  }

  Future<Map<String, dynamic>> updateResource(
    String endpoint,
    Map<String, dynamic> data,
  ) async {
    return await _httpService.put('$baseUrl/$endpoint', body: data);
  }

  Future<Map<String, dynamic>> deleteResource(String endpoint) async {
    return await _httpService.delete('$baseUrl/$endpoint');
  }

  void dispose() {
    _httpService.dispose();
  }
}

